import React from 'react';
import { Link } from 'react-router-dom';
import { useTheme } from '../App';

const Hero = () => {
  const { isDark } = useTheme();

  return (
    <section className="relative min-h-[90vh] flex items-center overflow-hidden">
      {/* Background Image */}
      <div className="absolute inset-0 z-0">
        <img
          src="https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?ixlib=rb-4.0.3&auto=format&fit=crop&w=2070&q=80"
          alt="Restaurant interior"
          className="w-full h-full object-cover"
        />
        <div className={`absolute inset-0 ${isDark ? 'bg-dark-200/85' : 'bg-gray-900/70'}`} />
      </div>

      {/* Content */}
      <div className="container-custom relative z-10 pt-20 pb-16">
        <div className="max-w-3xl">
          <span className="inline-block px-4 py-2 bg-primary-500/20 text-primary-400 rounded-full text-sm font-medium mb-6 animate-fade-in">
            Welcome to MH Restaurant
          </span>
          <h1 className="text-4xl md:text-5xl lg:text-6xl font-display font-bold text-white mb-6 animate-slide-up">
            Experience Fine{' '}
            <span className="text-primary-500">Dining</span>{' '}
            Like Never Before
          </h1>
          <p className={`text-lg md:text-xl ${isDark ? 'text-gray-300' : 'text-gray-200'} mb-8 max-w-2xl animate-slide-up`} style={{ animationDelay: '0.2s' }}>
            Discover exquisite flavors crafted with passion and the finest ingredients. 
            Join us for an unforgettable culinary journey that will delight your senses.
          </p>
          <div className="flex flex-col sm:flex-row gap-4 animate-slide-up" style={{ animationDelay: '0.4s' }}>
            <Link to="/menu" className="btn-primary text-center">
              View Our Menu
            </Link>
            <Link to="/contact" className="btn-secondary border-white text-white hover:bg-white hover:text-gray-900 text-center">
              Book a Table
            </Link>
          </div>
        </div>
      </div>

      {/* Decorative Elements */}
      <div className="absolute bottom-0 left-0 w-full h-24 bg-gradient-to-t from-black/30 to-transparent" />
      
      {/* Scroll Indicator */}
      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 animate-bounce">
        <svg className="w-6 h-6 text-white/70" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 14l-7 7m0 0l-7-7m7 7V3" />
        </svg>
      </div>
    </section>
  );
};

export default Hero;
